const incident = $input.first().json;
const now = new Date().toISOString();
let llmSummary = `Automated analysis: ${incident.tier} threat detected with score ${incident.risk_score}/100. Verdict: ${incident.verdict}. Immediate human review recommended.`;
try {
  const prompt = `You are a senior fraud analyst at Barclays. Risk Score: ${incident.risk_score}/100. Tier: ${incident.tier}. Verdict: ${incident.verdict}. Top Indicators: ${(incident.top_indicators||[]).join(', ')}. Write a 2-sentence professional incident summary.`;
  const resp = await fetch('http://localhost:11434/api/generate', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ model: 'llama3', prompt, stream: false }), signal: AbortSignal.timeout(8000) });
  if (resp.ok) { const data = await resp.json(); if (data.response) llmSummary = data.response.trim(); }
} catch(e) {}
return [{ json: { ...incident, llm_summary: llmSummary, audit_trail: `[${now}] FraudShield detected ${incident.tier} threat. Score: ${incident.risk_score}/100. LLM: ${llmSummary}` } }];

const d = $input.first().json;
const baseUrl = 'http://localhost:5678/webhook/fraudshield-approval';
const approveUrl = `${baseUrl}?incident_id=${d.incident_id}&approved=true&prediction_id=${d.prediction_id}`;
const rejectUrl  = `${baseUrl}?incident_id=${d.incident_id}&approved=false&prediction_id=${d.prediction_id}`;
const indicatorsList = (d.top_indicators || []).map(i => `<li style='margin:4px 0;color:#333'>${i}</li>`).join('');
const html = `<!DOCTYPE html><html><head><meta charset='UTF-8'></head><body style='font-family:Segoe UI,Arial,sans-serif;max-width:600px;margin:0 auto;background:#f5f5f5;padding:20px'><div style='background:#00395d;color:white;padding:20px;border-radius:8px 8px 0 0'><h1 style='margin:0;font-size:22px'>🚨 CRITICAL Fraud Alert</h1><p style='margin:8px 0 0;opacity:0.8'>FraudShield AI — Barclays Incident Response</p></div><div style='background:white;padding:20px;border-radius:0 0 8px 8px'><p><strong>Incident:</strong> ${d.incident_id} | <strong>Score:</strong> ${d.risk_score}/100 | <strong>Tier:</strong> ${d.tier}</p><p><strong>AI Summary:</strong> ${d.llm_summary}</p><div style='text-align:center;margin-top:24px'><a href='${approveUrl}' style='background:#dc3545;color:white;padding:14px 32px;border-radius:6px;text-decoration:none;font-weight:700;margin-right:12px'>QUARANTINE EMAIL</a><a href='${rejectUrl}' style='background:#28a745;color:white;padding:14px 32px;border-radius:6px;text-decoration:none;font-weight:700'>MARK AS SAFE</a></div></div></body></html>`;
return [{ json: { ...d, approval_email_html: html, approve_url: approveUrl, reject_url: rejectUrl } }];

const d = $input.first().json;
const indicators = (d.top_indicators || []).slice(0, 3).join(' | ');
return [{ json: { ...d, slack_message: `*HIGH Risk Email Detected*
*Score:* ${d.risk_score}/100  *Tier:* ${d.tier}
*Verdict:* ${d.verdict}  *Action:* ${d.outlook_action}
*AI Summary:* ${d.llm_summary}
*Top Indicators:* ${indicators}
*Incident ID:* ${d.incident_id}`, notification_type: 'HIGH' } }];

