return [{ json: { ...incident, action_taken: 'QUARANTINE_CONFIRMED', analyst_decision: 'QUARANTINE', analyst_decision_at: now, feedback_for_model: 'PHISHING', audit_trail: incident.audit_trail + ` [${now}] Human analyst APPROVED quarantine.`, feedback_payload: { prediction_id: incident.prediction_id, user_verdict: 'PHISHING', model_verdict: incident.verdict, model_score: incident.risk_score, notes: `n8n: analyst confirmed QUARANTINE for ${incident.incident_id}` } } }];

